/**
 * Ensures Flowbite Tailwind `@source "../.flowbite-react/class-list.json"` exists before dev/build.
 * The file content is regenerated by the Flowbite Next.js plugin during build/dev.
 */
import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const root = path.join(__dirname, "..");
const dir = path.join(root, ".flowbite-react");
const target = path.join(dir, "class-list.json");

if (!fs.existsSync(target)) {
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(target, "[]\n", "utf8");
}
